const express = require('express');
const app = express();

const allowlist = {
  'home': '/home',
  'dashboard': '/dashboard',
  'profile': '/profile'
};

app.get('/oauth/callback', (req, res) => {
  const returnId = req.query.return_url;
  const redirectPath = allowlist[returnId];

  if (redirectPath) {
    res.redirect(redirectPath);
  } else {
    res.status(400).send('Invalid return URL');
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});